class Solution {
public:
    int strangePrinter(string s) {
        int n = s.size();
        vector<vector<int>> dp(n, vector<int>(n, 0));
        for (int i = n - 1; i >= 0; --i) {
            dp[i][i] = 1;
            for (int j = i + 1; j < n; ++j) {
                dp[i][j] = dp[i + 1][j] + 1;
                if (s[i] == s[j]) {
                    dp[i][j] = min(dp[i][j], dp[i][j - 1] + (j - 1 >= i + 1 ? dp[i + 1][j - 1] : 0));
                } else {
                    for (int k = i + 1; k < j; ++k) {
                        if (s[i] == s[k]) {
                            dp[i][j] = min(dp[i][j], dp[i][k] + dp[k + 1][j]);
                        }
                    }
                }
            }
        }
        return dp[0][n - 1];
    }
};
